     const Icon(Icons.hourglass_empty, color: Colors.amber, size: 20),                 const SizedBox(width: 8),                 Text(                   'Còn lại: ${user.remainingDays ?? 0} ngày',                   style: const TextStyle(                     color: Colors.amber,                     fontSize: 16,                     fontWeight: FontWeight.w600,                   ),                 ),               ],             ),           ),         ],       ),     );   }
